import vex
from ag2 import GroupChat, Agent

# Install: pip install ag2 vex-sdk

@vex.hook(pii_patterns=[r'\b\d{3}-\d{2}-\d{4}\b', r'\b[A-Z][a-z]+ [A-Z][a-z]+\b SSN\b'])
def insurance_compliance_check(messages):
    for msg in messages:
        if 'discriminate' in msg['content'].lower() or 'protected class' in msg['content'].lower():
            return {'block': True, 'reason': 'Discriminatory language detected'}
        if vex.detect_pii(msg['content']):
            return {'block': True, 'reason': 'PII exposure violation (GDPR/CCPA)'}
    return {'allow': True}

# Register in AG2
groupchat = GroupChat(agents=[agent1, agent2], message_hook=insurance_compliance_check)

print('Vex hook registered for AG2 insurance compliance')

import vex
from ag2 import CodeExecutorAgent

@vex.hook(risk_keywords=['deny', 'reject', 'decline'])
def claims_explainability_check(messages):
    for msg in messages:
        if 'deny' in msg['content'] and 'reason:' not in msg['content']:
            return {'block': True, 'reason': 'NAIC explainability violation - missing denial rationale'}
    vex.audit_log(messages, category='claims_processing')
    return {'allow': True}

code_agent = CodeExecutorAgent(message_hook=claims_explainability_check)
print('Claims explainability hook active')

import vex
from ag2 import GroupChatManager

@vex.hook(compliance='underwriting')
def speaker_bias_monitor(participants, selected_speaker):
    protected_terms = ['race', 'gender', 'ethnicity']
    speaker_history = vex.get_session_history()
    if len([s for s in speaker_history[-5:] if s == selected_speaker]) > 3:
        return {'block': True, 'reason': 'Speaker selection bias detected - FCRA violation risk'}
    return {'allow': True}

manager = GroupChatManager(speaker_hook=speaker_bias_monitor)
print('Anti-bias speaker monitoring enabled')
